        SANCTION_IS_A_MAGIC_SPELL_THAT_WE_USE                                = 10825,  -- Sanction is a magic spell that we use to observe and assess mercenaries' actions.
        DEFEATING_ENEMIES_WHILE_YOU_HAVE_SANCTION_CAST_ON                    = 10826,  -- Defeating enemies while you have Sanction cast on you will raise your Imperial Standing. Also, the stronger the monsters you fight, the higher your Imperial Standing will become.
        WHEN_FIGHTING_IN_A_BEASTMAN_STRONGHOLD_THAT_HAS                      = 10827,  -- When fighting in a beastman stronghold that has taken the Astral Candescence, your Imperial Standing will rise by a significant amount as thanks for your participation in the recovery effort.
