        YOU_NEED_NOT_KNOW_WHAT_THE_ASTRAL_CANDESCENCE                        = 10837,  -- You need not know what the Astral Candescence is.
        ALL_YOU_MUST_KNOW_IS_THAT_IT_IS                                      = 10838,  -- All you must know is that it is your duty to protect the five Serpent Generals who hold the keys to the Hall of Binding, and to drive the beastman hordes from the Imperial capital.
        THE_EMPIRE_S_SAFETY_AND_ITS_FUTURE_REST                              = 10839,  -- The Empire's safety and its future rest on your capable shoulders! Rest assured that you will be rewarded for your efforts.
        THE_EMPIRE_S_DEFENSE_IS_ENTRUSTED_TO_FIVE                            = 10840,  -- The Empire's defense is entrusted to five generals.
        EACH_POSSESSES_A_NAME_CORRESPONDING_TO_THE_SYMBOLS                   = 10841,  -- Each possesses a name corresponding to the symbols of the Empire--the serpents of flame, water, stone, gales, and sky.
        FURTHERMORE_THE_MIRRORS_USED_TO_OPEN_THE_HALL                        = 10842,  -- Furthermore, the mirrors used to open the Hall of Binding are divided among their possession. Thus, the generals' fates determine the tide of battle.
        IF_ALL_FIVE_GENERALS_SHOULD_FALL_IN_BATTLE                           = 10843,  -- If all five generals should fall in battle, the Hall of Binding will open, and the beastmen will be able to seize the Astral Candescence.
        IT_IS_YOUR_RESPONSIBILITY_TO_PREVENT_SUCH_A                          = 10844,  -- It is your responsibility to prevent such a disaster from happening. We are depending on you!
        WHEN_THE_ASTRAL_CANDESCENCE_IS_SAFELY_RESTING_ON                     = 10845,  -- When the Astral Candescence is safely resting on its plinth in the Hall of Binding, it emanates waves that bestow special bonuses to Sanction.
